CREATE TABLE organizations (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  name TEXT NOT NULL UNIQUE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL\n);\n\n-- Optional: Add RLS policies for organizations if needed\nALTER TABLE organizations ENABLE ROW LEVEL SECURITY;\n\nCREATE POLICY \"Allow public read access to organizations\" ON organizations FOR SELECT USING (TRUE);\n-- CREATE POLICY \"Allow authenticated users to insert organizations\" ON organizations FOR INSERT WITH CHECK (auth.role() = \'authenticated\');\n-- CREATE POLICY \"Allow authenticated users to update organizations\" ON organizations FOR UPDATE USING (auth.role() = \'authenticated\');\n-- CREATE POLICY \"Allow authenticated users to delete organizations\" ON organizations FOR DELETE USING (auth.role() = \'authenticated\');\n